import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classicFour() {
        // [1,2,3,1]: rob idx 0 (1) + idx 2 (3) = 4
        assertEquals(4, new Solution().rob(new int[]{1, 2, 3, 1}));
    }

    @Test
    void classicFive() {
        // [2,7,9,3,1]: rob idx 0 (2) + idx 2 (9) + idx 4 (1) = 12
        assertEquals(12, new Solution().rob(new int[]{2, 7, 9, 3, 1}));
    }

    @Test
    void emptyArray() {
        assertEquals(0, new Solution().rob(new int[]{}));
    }

    @Test
    void singleHouse() {
        assertEquals(5, new Solution().rob(new int[]{5}));
    }

    @Test
    void twoHouses() {
        // Pick the larger of the two
        assertEquals(7, new Solution().rob(new int[]{3, 7}));
    }

    @Test
    void symmetricEnds() {
        // [2,1,1,2]: rob idx 0 (2) + idx 3 (2) = 4
        assertEquals(4, new Solution().rob(new int[]{2, 1, 1, 2}));
    }

    @Test
    void allSameValue() {
        // [3,3,3,3,3]: alternating gives ceil(5/2)*3 = 9
        assertEquals(9, new Solution().rob(new int[]{3, 3, 3, 3, 3}));
    }
}
